import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.DeNJmwJc.js";const p=JSON.parse('{"title":"Chapter 36 — Marks","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/36-marks.md","filePath":"chapters/36-marks.md"}'),d={name:"chapters/36-marks.md"};function s(i,t,c,n,l,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="chapter-36-—-marks" tabindex="-1">Chapter 36 — Marks <a class="header-anchor" href="#chapter-36-—-marks" aria-label="Permalink to &quot;Chapter 36 — Marks&quot;">​</a></h1><blockquote><p><em>&quot;Set bookmarks in your files and jump between them instantly.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Marks let you save cursor positions and jump back to them later.</p><hr><h1 id="setting-and-using-marks" tabindex="-1">Setting and Using Marks <a class="header-anchor" href="#setting-and-using-marks" aria-label="Permalink to &quot;Setting and Using Marks&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>ma</code></td><td>Set mark named <code>a</code></td></tr><tr><td><code>&#39;a</code></td><td>Jump to <strong>line</strong> of mark <code>a</code></td></tr><tr><td><code>`a</code></td><td>Jump to <strong>exact position</strong> of mark <code>a</code></td></tr><tr><td><code>:marks</code></td><td>List all marks</td></tr></tbody></table><hr><h1 id="types-of-marks" tabindex="-1">Types of Marks <a class="header-anchor" href="#types-of-marks" aria-label="Permalink to &quot;Types of Marks&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Mark</th><th>Scope</th><th>Description</th></tr></thead><tbody><tr><td><code>a</code>-<code>z</code></td><td>File-local</td><td>Visible only in current file</td></tr><tr><td><code>A</code>-<code>Z</code></td><td>Global</td><td>Visible across all files</td></tr><tr><td><code>0</code>-<code>9</code></td><td>Special</td><td>Set in <code>.viminfo</code>, persist across sessions</td></tr></tbody></table><hr><h1 id="special-marks" tabindex="-1">Special Marks <a class="header-anchor" href="#special-marks" aria-label="Permalink to &quot;Special Marks&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Mark</th><th>Position</th></tr></thead><tbody><tr><td><code>`</code></td><td>Position before last jump</td></tr><tr><td><code>&#39;.</code></td><td>Position of last change</td></tr><tr><td><code>&#39;^</code></td><td>Position of last insert</td></tr><tr><td><code>&#39;[</code></td><td>Start of last change/yank</td></tr><tr><td><code>&#39;]</code></td><td>End of last change/yank</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>ma</code> sets mark <code>a</code>, <code>&#39;a</code> jumps to it.</li><li>Lowercase = file-local, uppercase = global.</li><li>Special marks track jump history.</li><li><code>:marks</code> lists all marks.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Set a mark with <code>ma</code>, jump away, return with <code>&#39;a</code>.</li><li>Set a global mark with <code>mA</code>, open another file, jump back.</li><li>Use <code>&#39;. </code> to jump to the last edit location.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./37-macros.html"><strong>Chapter 37 — Macros</strong></a></p><p>Record and replay sequences of commands.</p>',26)])])}const u=e(d,[["render",s]]);export{p as __pageData,u as default};
